-- crypt.base64 ŌĆō pure-Lua, no null bytes (Roblox forbids string.char(0))
local function b64dec(s)
  local b='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
  s=s:gsub('[^'..b..'=]','')
  local bits=''
  s:gsub('.',function(c)
    if c=='=' then bits=bits..'000000';return end
    local idx=b:find(c,1,true)-1
    for i=5,0,-1 do bits=bits..(math.floor(idx/2^i)%2==1 and '1' or '0') end
  end)
  local out={}
  for i=1,#bits-7,8 do
    local byte=0
    for j=0,7 do byte=byte+(bits:sub(i+j,i+j)=='1' and 2^(7-j) or 0) end
    if byte>0 then out[#out+1]=string.char(byte) end  -- skip null bytes
  end
  return table.concat(out)
end

if not crypt then
  crypt={base64={decode=b64dec,encode=function(s)
    local b='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    return((s:gsub('.',function(c)
      local byte=string.byte(c)
      local bits=''
      for i=7,0,-1 do bits=bits..(math.floor(byte/2^i)%2==1 and'1'or'0')end
      return bits
    end)..'0000'):gsub('%d%d%d%d%d%d',function(x)
      local n=0
      for i=1,6 do n=n*2+(x:sub(i,i)=='1'and 1 or 0)end
      return b:sub(n+1,n+1)
    end)..({'','==','='})[#s%3+1])
  end}}
else
  if not crypt.base64 then crypt.base64={} end
  if not crypt.base64.decode then crypt.base64.decode=b64dec end
end

