local function detectExec()
  if identifyexecutor then local ok,n=pcall(identifyexecutor);if ok and n then return tostring(n)end end
  if getexecutorname  then local ok,n=pcall(getexecutorname); if ok and n then return tostring(n)end end
  if EXECUTOR_NAME then return tostring(EXECUTOR_NAME)end
  if syn     then return'Synapse'end
  if KRNL_LOADED then return'Krnl'end
  if fluxus  then return'Fluxus'end
  if wave    then return'Wave'end
  if getgenv and getgenv().Delta then return'Delta'end
  return'Unknown'
end
