        tween:Play()
    else
        local tween = TweenService:Create(toggleButton, TweenInfo.new(0.2, Enum.EasingStyle.Quart), {BackgroundColor3 = Color3.fromRGB(100, 200, 100)})
        tween:Play()
    end
end)

-- Minimize functionality
local function toggleMinimize()
    isMinimized = not isMinimized
    local tweenInfo = TweenInfo.new(0.4, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
    
    if isMinimized then
        local tween = TweenService:Create(mainFrame, tweenInfo, {Size = UDim2.new(0, 180, 0, 30)})
        tween:Play()
        contentFrame.Visible = false
    else
        local tween = TweenService:Create(mainFrame, tweenInfo, {Size = UDim2.new(0, 180, 0, 80)})
        tween:Play()
        contentFrame.Visible = true
    end
end

minimizeButton.MouseButton1Click:Connect(toggleMinimize)

-- Close functionality
closeButton.MouseButton1Click:Connect(function()
    local tweenInfo = TweenInfo.new(0.3, Enum.EasingStyle.Quart, Enum.EasingDirection.In)
    local tween = TweenService:Create(mainFrame, tweenInfo, {
        Size = UDim2.new(0, 0, 0, 0),
        BackgroundTransparency = 1
    })
    tween:Play()
    
    tween.Completed:Connect(function()
        screenGui:Destroy()
        if heartbeatConnection then
            heartbeatConnection:Disconnect()
        end
    end)
end)

-- Anti-kidnap functionality
local function disableSitting()
    local character = player.Character
    if character then
        local humanoid = character:FindFirstChild("Humanoid")
        if humanoid then
            -- Disable seated state
            humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, false)
            
            -- Monitor and force unseat if somehow seated
            if heartbeatConnection then
                heartbeatConnection:Disconnect()
            end
            
            heartbeatConnection = RunService.Heartbeat:Connect(function()
                if humanoid.Sit then
                    humanoid.Sit = false
                end
                
                -- Check if somehow still in seated state
                if humanoid:GetState() == Enum.HumanoidStateType.Seated then
                    humanoid:ChangeState(Enum.HumanoidStateType.Running)
                end
                
                -- Destroy any seat welds
                local rootPart = character:FindFirstChild("HumanoidRootPart")
                if rootPart then
                    local seatWeld = rootPart:FindFirstChild("SeatWeld")
                    if seatWeld then
                        seatWeld:Destroy()
                    end
                end
            end)
        end
    end
end

local function enableSitting()
    local character = player.Character
    if character then
        local humanoid = character:FindFirstChild("Humanoid")
        if humanoid then
            -- Re-enable seated state
            humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, true)
        end
    end
    
    -- Disconnect monitoring
    if heartbeatConnection then
        heartbeatConnection:Disconnect()
        heartbeatConnection = nil
    end
end

local function updateToggleVisuals()
    local tweenInfo = TweenInfo.new(0.3, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
    
    if antiKidnapEnabled then
        -- Change to enabled state
        local buttonTween = TweenService:Create(toggleButton, tweenInfo, {
            BackgroundColor3 = Color3.fromRGB(100, 200, 100),
            TextColor3 = Color3.fromRGB(255, 255, 255)
        })
        
        buttonTween:Play()
        
        toggleButton.Text = "Disable"
    else
        -- Change to disabled state
        local buttonTween = TweenService:Create(toggleButton, tweenInfo, {
            BackgroundColor3 = Color3.fromRGB(70, 70, 70),
            TextColor3 = Color3.fromRGB(255, 255, 255)
        })
        
        buttonTween:Play()
        
        toggleButton.Text = "Enable"
    end
end

-- Toggle button functionality
toggleButton.MouseButton1Click:Connect(function()
    antiKidnapEnabled = not antiKidnapEnabled
    
    if antiKidnapEnabled then
        disableSitting()
    else
        enableSitting()
    end
    
    updateToggleVisuals()
end)

-- Handle character respawning
player.CharacterAdded:Connect(function()
    wait(1) -- Wait for character to fully load
    if antiKidnapEnabled then
        disableSitting()
    end
end)

-- Initial setup
if player.Character then
    if antiKidnapEnabled then
        disableSitting()
    end
end

]]
SCRIPTS["antislide"]=[[
-- Function to adjust the physical properties of character parts
local function passePhysikAn(character)
    -- Iterate over all MeshParts and Parts in the character
    for _, teil in ipairs(character:GetDescendants()) do
        if teil:IsA("MeshPart") or teil:IsA("Part") then
            -- High values for instant stopping and constant speed
            -- Parameters: Density, Friction, Elasticity, FrictionWeight, ElasticityWeight
            local physikalischeEigenschaften = PhysicalProperties.new(5.0, 3.0, 0.05, 3.0, 0.3)
            teil.CustomPhysicalProperties = physikalischeEigenschaften
            
            -- Set linear velocity to a constant based on movement
            teil.AssemblyLinearVelocity = Vector3.new(0, 0, 0)
        end
    end
end

-- Get the local player
local spieler = game.Players.LocalPlayer

-- Function to continuously update character's velocity
local function aktualisiereGeschwindigkeit(character)
    -- Monitor movement continuously
    game:GetService("RunService").Heartbeat:Connect(function()
        local humanoid = character:FindFirstChild("Humanoid")
        if humanoid then
            local zielGeschwindigkeit
            if humanoid.MoveDirection.Magnitude < 0.1 then
                -- Stop immediately if the player tries to halt
                zielGeschwindigkeit = Vector3.new(0, 0, 0)
            else
                -- Set full speed constant when moving
                local geschwindigkeitsMultiplikator = 1
                if humanoid.WalkSpeed > 16 then -- Player is sprinting
                    geschwindigkeitsMultiplikator = 1.5
                end
                zielGeschwindigkeit = humanoid.MoveDirection.Unit * (humanoid.WalkSpeed * geschwindigkeitsMultiplikator)
            end
            
            -- Set the target speed directly for all parts
            for _, teil in ipairs(character:GetDescendants()) do
                if teil:IsA("BasePart") then
                    teil.AssemblyLinearVelocity = Vector3.new(
                        zielGeschwindigkeit.X,
                        teil.AssemblyLinearVelocity.Y,
                        zielGeschwindigkeit.Z
                    )
                end
            end
        end
    end)
end

-- Apply properties if the character already exists
if spieler.Character then
    passePhysikAn(spieler.Character)
    aktualisiereGeschwindigkeit(spieler.Character)
end

-- Apply properties when the character spawns
spieler.CharacterAdded:Connect(function(neuerCharakter)
    passePhysikAn(neuerCharakter)
    aktualisiereGeschwindigkeit(neuerCharakter)
end)

]]
SCRIPTS["antivcban"]=[[
-- Anti VC Ban (executor-compatible)
local function disableEvent(ev)
  local gc=(getconnections and getconnections(ev)) or {}
  for _,c in ipairs(gc) do pcall(function()c:Disable()end) end
end
pcall(function()
  local vcs=game:GetService("VoiceChatService")
  local vci=game:GetService("VoiceChatInternal")
  local cf=clonefunction or function(f)return f end
  cf(vcs.rejoinVoice)(vcs)
  task.wait(0.02)
  disableEvent(vcs.VoiceChatStatsCollected)
  disableEvent(vci.StateChanged)
end)
]]
