        tg.Text = "ON"
        tg.TextColor3 = Color3.new(1, 1, 1)
    else
        tg.Text = "OFF"
        tg.TextColor3 = Color3.new(0.9, 0.9, 0.9)
    end
end)

cb.MouseButton1Click:Connect(function()
    sg:Destroy()
