ColorSequenceKeypoint.new(0,Color3.fromRGB(255,255,255)),
ColorSequenceKeypoint.new(1,cl)
}
wv.BackgroundColor3=Color3.fromHSV(hu,sa,1)
gv.Color=ColorSequence.new{
