ColorSequenceKeypoint.new(1,Color3.fromHSV(hu,sa,1))
}
local fc=Color3.fromHSV(hu,sa,va)
pv.BackgroundColor3=fc
if md==1 then
bg=fc
b1.BackgroundColor3=fc
bc.BackgroundColor3=fc
else
tx=fc
b2.BackgroundColor3=fc
bc.TextColor3=fc
end
end

local function us(pc)
sa=pc
