          local rx = ip.Position.X - sr.AbsolutePosition.X
          local pc = math.clamp(rx / sr.AbsoluteSize.X, 0, 1)
          local vl = mn + (mx - mn) * pc
          
          us(sr, hn, vl, mn, mx)
          cb(vl)
        end
      end)
      
      us(sr, hn, iv, mn, mx)
    end

