local oS = UDim2.new(0, 200, 0, 100)

local function tM()
    if iM then
        Ts:Create(Mf, TweenInfo.new(0.3, Enum.EasingStyle.Quart), {Size = oS}):Play()
        Mb.Text = "ŌłÆ"
        Tb.Visible = true
        Kb.Visible = true
        Kl.Visible = true
        iM = false
    else
        Ts:Create(Mf, TweenInfo.new(0.3, Enum.EasingStyle.Quart), {Size = UDim2.new(0, 200, 0, 30)}):Play()
        Mb.Text = "+"
        Tb.Visible = false
        Kb.Visible = false
        Kl.Visible = false
        iM = true
    end
end

