SCRIPTS["ndgodmode"]=[[
local runsvc = game:GetService("RunService")
local heartbeat = runsvc.Heartbeat
local rstepped = runsvc.RenderStepped
local players = game:GetService("Players")

local lp = players.LocalPlayer
local novel = Vector3.zero

local function noDamage(chr)
    local root = chr:WaitForChild("HumanoidRootPart")
    local humanoid = chr:WaitForChild("Humanoid")

    if root and humanoid then
        -- Prevent fall damage
        local rootCon
        rootCon = heartbeat:Connect(function()
            if not root.Parent then
                rootCon:Disconnect()
                return
            end

            local oldVel = root.AssemblyLinearVelocity
            root.AssemblyLinearVelocity = novel

            rstepped:Wait()
            root.AssemblyLinearVelocity = oldVel
        end)

        -- Prevent all other types of damage
        local healthCon
        healthCon = humanoid.HealthChanged:Connect(function(health)
            if health < humanoid.MaxHealth then
                humanoid.Health = humanoid.MaxHealth
            end
        end)

        -- Cleanup connections on character removal
        chr.AncestryChanged:Connect(function(_, parent)
            if not parent then
                if rootCon then rootCon:Disconnect() end
                if healthCon then healthCon:Disconnect() end
            end
        end)
    end
end

-- Apply no damage to the current character
if lp.Character then
    noDamage(lp.Character)
end

-- Apply no damage to future characters
lp.CharacterAdded:Connect(noDamage)

]]
SCRIPTS["pianoplayer"]=[[
local Players = game:GetService("Players")
local UserInputService = game:GetService("UserInputService")
local VirtualInputManager = game:GetService("VirtualInputManager")
local RunService = game:GetService("RunService")

local player = Players.LocalPlayer
local playerGui = player:WaitForChild("PlayerGui")

local function pressKey(keyName, needsShift)
    needsShift = needsShift or false
    
    local keyCode = Enum.KeyCode[keyName]
    if keyCode then
        if needsShift then
            VirtualInputManager:SendKeyEvent(true, Enum.KeyCode.LeftShift, false, game)
            wait(0.05)
        end
        
        VirtualInputManager:SendKeyEvent(true, keyCode, false, game)
        wait(0.1)
        VirtualInputManager:SendKeyEvent(false, keyCode, false, game)
        
        if needsShift then
            VirtualInputManager:SendKeyEvent(false, Enum.KeyCode.LeftShift, false, game)
        end
        
        return keyName
    end
    return nil
end

-- Function to press multiple keys simultaneously (for chords)
local function pressChord(keys)
    -- Press all keys down
    for _, keyName in ipairs(keys) do
        local keyCode = Enum.KeyCode[keyName]
        if keyCode then
            VirtualInputManager:SendKeyEvent(true, keyCode, false, game)
        end
    end
    
    wait(0.1)
    
    -- Release all keys
    for _, keyName in ipairs(keys) do
        local keyCode = Enum.KeyCode[keyName]
        if keyCode then
            VirtualInputManager:SendKeyEvent(false, keyCode, false, game)
        end
    end
end

local screenGui = Instance.new("ScreenGui")
screenGui.Name = "PianoAutoPlayer2025"
screenGui.Parent = playerGui

local mainFrame = Instance.new("Frame")
mainFrame.Size = UDim2.new(0, 300, 0, 280)
mainFrame.Position = UDim2.new(0.5, -150, 0, 50)
mainFrame.BackgroundColor3 = Color3.new(0, 0, 0)
mainFrame.BackgroundTransparency = 0.8
mainFrame.BorderSizePixel = 0
mainFrame.Active = true
mainFrame.Draggable = true
mainFrame.Parent = screenGui

local corner = Instance.new("UICorner")
corner.CornerRadius = UDim.new(0, 10)
corner.Parent = mainFrame

local stroke = Instance.new("UIStroke")
stroke.Color = Color3.new(0.2, 0.2, 0.2)
stroke.Transparency = 0.5
stroke.Thickness = 1
stroke.Parent = mainFrame

-- Invisible title bar
local titleBar = Instance.new("Frame")
titleBar.Size = UDim2.new(1, 0, 0, 30)
titleBar.Position = UDim2.new(0, 0, 0, 0)
titleBar.BackgroundTransparency = 1
titleBar.Parent = mainFrame

local titleLabel = Instance.new("TextLabel")
titleLabel.Size = UDim2.new(1, 0, 1, 0)
titleLabel.Position = UDim2.new(0, 0, 0, 0)
titleLabel.BackgroundTransparency = 1
titleLabel.Text = "Piano Auto-Player 2025"
titleLabel.TextColor3 = Color3.new(0.8, 0.8, 0.8)
titleLabel.TextSize = 14
titleLabel.Font = Enum.Font.GothamBold
titleLabel.Parent = titleBar

local statusLabel = Instance.new("TextLabel")
statusLabel.Size = UDim2.new(1, 0, 0, 25)
statusLabel.Position = UDim2.new(0, 0, 0, 35)
statusLabel.BackgroundTransparency = 1
statusLabel.Text = "Ready"
statusLabel.TextColor3 = Color3.new(0.8, 0.8, 0.8)
statusLabel.TextSize = 12
statusLabel.Font = Enum.Font.Gotham
statusLabel.Parent = mainFrame

local songs = {
    ["Never Meant to Belong - Bleach (I Hate the Rain)"] = {
        keys = {
            -- Opening phrase - slow chords (measures 1-4)
            {"Six", "R", "T", "U"}, {"R", "T", "U"}, {"E", "T", "U"}, {"E", "T", "U"},
            {"Five", "R", "T", "U"}, {"R", "T", "U"}, {"E", "T", "U"}, {"E", "T", "U"},
            {"Four", "R", "T", "U"}, {"R", "T", "U"}, {"E", "T", "U"}, {"E", "T", "U"},
            {"Three", "E", "R", "U"}, {"E", "R", "U"}, {"R", "U"}, "W",
            
            -- High melody section (measures 5-8)
            "K", "L", "X", "Z", "Six", "Six", "Five", "Five",
            "K", "L", "X", "Z", "Four", "Four", "Three", "Three",
            "K", "L", "V", "X", "Six", {"Z", "X"}, "Six", {"Z", "Five", "X"},
            {"Z", "X"}, "Five", "C", {"Four", "X"}, "Z", "L", "K", "Four",
            "J", "H", {"Three", "G"}, "G", "F", "Three",
            
