	hl.FillTransparency = 1
	hl.OutlineTransparency = 1

	local bl = Instance.new("BlurEffect")
	bl.Parent = cm
	bl.Size = 0

	task.wait(0.5)

	t1:Play()
	t1.Looped = true
	s1:Play()

	for i = 0, 1, 0.05 do
		hl.FillTransparency = 1 - i * 0.5
		hl.OutlineTransparency = 1 - i
		bl.Size = i * 15
		task.wait()
	end

	task.wait(3)

	t1.Looped = false
	t1:Stop()

	for i = 1, 0, -0.1 do
		hl.FillTransparency = 1 - i * 0.5
		hl.OutlineTransparency = 1 - i
		bl.Size = i * 15
		task.wait()
	end

	hl:Destroy()
	bl:Destroy()

	for _, tr in pairs(hm:GetPlayingAnimationTracks()) do
		if tr ~= t2 then
			tr:Stop()
		end
	end

	s2:Play()
	t2:Play()
	task.wait(4)

	t2:Stop()
	s2:Stop()
	
	ac = false
end)

]]
SCRIPTS["sfly"]=[[
local UserInputService = game:GetService("UserInputService")
if UserInputService.TouchEnabled then
    loadstring(game:HttpGet("https://absent.wtf/supermanfly.lua"))()
else
    loadstring(game:HttpGet("https://absent.wtf/supermanflyjj.lua"))()
end

]]
