local function safeRun(key)
  local code=SCRIPTS[key]
  if not code then return end
  task.spawn(function()
    local fn,err=loadstring(code)
    if fn then
      local ok2,er2=pcall(fn)
      if not ok2 then warn("[AC] "..key..": "..tostring(er2)) end
    else
      warn("[AC] parse err "..key..": "..tostring(err))
    end
  end)
end

