-- Toasts
local tBusy=false;local tQ={}
local function toast(ttl,body,dur)
  dur=dur or 2.2;table.insert(tQ,{t=ttl,b=body,d=dur})
  if tBusy then return end;tBusy=true
  task.spawn(function()
    while #tQ>0 do
      local it=table.remove(tQ,1)
      local f=Instance.new("Frame",sg)
      f.AnchorPoint=Vector2.new(1,0)
      f.Size=UDim2.new(0,235,0,50)
      f.Position=UDim2.new(1,-68,0,-60)
      f.BackgroundColor3=Color3.fromRGB(8,4,16)
      f.BackgroundTransparency=0.2;f.BorderSizePixel=0;f.ZIndex=50;mkC(f,9)
      local st=Instance.new("UIStroke",f)
      st.Color=Color3.fromRGB(140,60,255);st.Thickness=1.2;st.Transparency=0.25
      local l1=Instance.new("TextLabel",f)
      l1.Size=UDim2.new(1,-12,0,16);l1.Position=UDim2.new(0,8,0,6)
      l1.BackgroundTransparency=1;l1.Text=it.t
      l1.TextColor3=Color3.fromRGB(160,80,255);l1.TextSize=10
      l1.Font=Enum.Font.GothamBold;l1.TextXAlignment=Enum.TextXAlignment.Left;l1.ZIndex=50
      local l2=Instance.new("TextLabel",f)
      l2.Size=UDim2.new(1,-12,0,16);l2.Position=UDim2.new(0,8,0,27)
      l2.BackgroundTransparency=1;l2.Text=it.b
      l2.TextColor3=Color3.fromRGB(200,185,220);l2.TextSize=10
      l2.Font=Enum.Font.Gotham;l2.TextXAlignment=Enum.TextXAlignment.Left;l2.ZIndex=50
      tw(f,{Position=UDim2.new(1,-68,0,14)},0.22)
      task.wait(it.d)
      tw(f,{Position=UDim2.new(1,-68,0,-65),BackgroundTransparency=1},0.18)
      task.wait(0.22);f:Destroy();task.wait(0.05)
    end
    tBusy=false
  end)
end

