local function posBar(anim)
  -- bar right edge = screen right - MG ŌåÆ X offset from right = MG
  -- bar center X from right = MG + BW/2 = 10+23 = 33
  local barCX=MG+BW/2
  local barH=bar.AbsoluteSize.Y
  local bP,aP,aT
  if barTop then
    bP=UDim2.new(1,-MG,0,MG)
    aP=UDim2.new(1,-barCX,0,MG+barH+3)
    aT="v"
  else
    bP=UDim2.new(1,-MG,1,-(barH+MG))
    aP=UDim2.new(1,-barCX,1,-(barH+MG+23))
    aT="^"
  end
  arr.Text=aT
  if anim then
    tw(bar,{Position=bP},0.3);tw(arr,{Position=aP},0.3)
  else
    bar.Position=bP;arr.Position=aP
  end
end

-- Initial position after first render
