local function getTagCfg(p)
  local w=WL[p.UserId]
  if w then
    return w.role,w.rc,w.tc,"rbxthumb://type=AvatarHeadShot&id="..p.UserId.."&w=150&h=150"
  end
  return DEF_ROLE,DEF_RC,DEF_TC,"rbxthumb://type=AvatarHeadShot&id="..p.UserId.."&w=150&h=150"
end

local function typeFx(lbl,txt)
  task.spawn(function()
    while lbl and lbl.Parent do
      lbl.Text=""
      for i=1,#txt do
        if not(lbl and lbl.Parent)then return end
        lbl.Text=txt:sub(1,i);task.wait(0.055)
      end
      task.wait(2)
      for i=#txt,1,-1 do
        if not(lbl and lbl.Parent)then return end
        lbl.Text=txt:sub(1,i);task.wait(0.028)
      end
      task.wait(0.3)
    end
  end)
end

local function tpBehind(tp)
  task.spawn(function()
    local tc=tp.Character;if not tc then return end
    local tr=tc:FindFirstChild("HumanoidRootPart");if not tr then return end
    local mc=lp.Character;if not mc then return end
    local mr=mc:FindFirstChild("HumanoidRootPart");if not mr then return end
    mr.CFrame=tr.CFrame*CFrame.new(0,0,4)
  end)
end

local function buildTag(p)
  if tagDB[p] then
    pcall(function()
      if tagDB[p].full  and tagDB[p].full.Parent  then tagDB[p].full:Destroy()  end
      if tagDB[p].logo  and tagDB[p].logo.Parent  then tagDB[p].logo:Destroy()  end
    end)
    tagDB[p]=nil
  end
  local c=p.Character;if not c then return end
  local head=c:FindFirstChild("Head");if not head then return end
  local role,rc,tc,img=getTagCfg(p)

  local bb=Instance.new("BillboardGui")
  bb.Name="ACTagF";bb.Size=UDim2.new(0,180,0,52)
  bb.StudsOffset=Vector3.new(0,3.8,0);bb.AlwaysOnTop=false
  bb.ResetOnSpawn=false;bb.LightInfluence=0;bb.Enabled=false;bb.Parent=head

  local bg=Instance.new("Frame",bb)
  bg.Size=UDim2.new(1,0,1,0)
  bg.BackgroundColor3=Color3.fromRGB(8,4,18)
  bg.BackgroundTransparency=0.1;bg.BorderSizePixel=0;mkC(bg,8)
  local bgs=Instance.new("UIStroke",bg)
  bgs.Color=rc;bgs.Thickness=1.5;bgs.Transparency=0.15

  local iF=Instance.new("Frame",bg)
  iF.Size=UDim2.new(0,40,1,-6);iF.Position=UDim2.new(0,3,0,3)
  iF.BackgroundColor3=Color3.fromRGB(16,8,32)
  iF.BackgroundTransparency=0.1;iF.BorderSizePixel=0;mkC(iF,6)
  local iL=Instance.new("ImageLabel",iF)
  iL.Size=UDim2.new(1,-4,1,-4);iL.Position=UDim2.new(0,2,0,2)
  iL.BackgroundTransparency=1;iL.ScaleType=Enum.ScaleType.Fit
  iL.BorderSizePixel=0;iL.Image=img;mkC(iL,4)

  local rL=Instance.new("TextLabel",bg)
  rL.Size=UDim2.new(1,-50,0,22);rL.Position=UDim2.new(0,47,0,4)
  rL.BackgroundTransparency=1;rL.Text=""
  rL.TextColor3=tc;rL.TextSize=11
  rL.Font=Enum.Font.GothamBold;rL.TextXAlignment=Enum.TextXAlignment.Left
  typeFx(rL,role)

  local uL=Instance.new("TextLabel",bg)
  uL.Size=UDim2.new(1,-50,0,16);uL.Position=UDim2.new(0,47,0,28)
  uL.BackgroundTransparency=1;uL.Text="@"..p.Name
  uL.TextColor3=Color3.fromRGB(170,130,215);uL.TextSize=9
  uL.Font=Enum.Font.Gotham;uL.TextXAlignment=Enum.TextXAlignment.Left

  local cb=Instance.new("TextButton",bb)
  cb.Size=UDim2.new(1,0,1,0);cb.BackgroundTransparency=1;cb.Text="";cb.ZIndex=10
  cb.MouseButton1Click:Connect(function()tpBehind(p)end)

  local lb=Instance.new("BillboardGui")
  lb.Name="ACTagL";lb.Size=UDim2.new(0,40,0,40)
  lb.StudsOffset=Vector3.new(0,3.8,0);lb.AlwaysOnTop=false
  lb.ResetOnSpawn=false;lb.LightInfluence=0;lb.Enabled=false;lb.Parent=head

  local lbI=Instance.new("ImageLabel",lb)
  lbI.Size=UDim2.new(1,0,1,0);lbI.BackgroundTransparency=1
  lbI.Image=img;lbI.ScaleType=Enum.ScaleType.Fit;lbI.BorderSizePixel=0;mkC(lbI,20)

  local lbB=Instance.new("TextButton",lb)
  lbB.Size=UDim2.new(1,0,1,0);lbB.BackgroundTransparency=1;lbB.Text="";lbB.ZIndex=10
  lbB.MouseButton1Click:Connect(function()tpBehind(p)end)

  tagDB[p]={full=bb,logo=lb}
end

RunService.Heartbeat:Connect(function()
  if not tagsOn then return end
  local mc=lp.Character;if not mc then return end
  local mr=mc:FindFirstChild("HumanoidRootPart");if not mr then return end
  local myP=mr.Position
  for p,td in pairs(tagDB) do
    local pc=p.Character
    if pc then
      local pr=pc:FindFirstChild("HumanoidRootPart")
      if pr then
        local d=(myP-pr.Position).Magnitude
        if td.full then td.full.Enabled=(d<=NEAR) end
        if td.logo then td.logo.Enabled=(d>NEAR and d<=FAR) end
      end
    end
  end
end)

local function removeTag(p)
  if tagDB[p] then
    pcall(function()
      if tagDB[p].full  and tagDB[p].full.Parent  then tagDB[p].full:Destroy()  end
      if tagDB[p].logo  and tagDB[p].logo.Parent  then tagDB[p].logo:Destroy()  end
    end)
    tagDB[p]=nil
  end
end

local function tryTag(p)
  if not tagsOn or p==lp then return end
  if not isUser(p.UserId) then return end
  if not p.Character then return end
  buildTag(p)
end

local selfConn
local function buildSelf()
  if selfConn then selfConn:Disconnect() end
  if lp.Character then
    local c=lp.Character
    for _,n in ipairs({"ACTagF","ACTagL"}) do
      local t=c:FindFirstChild(n);if t then t:Destroy() end
    end
    if tagsOn then buildTag(lp) end
  end
  selfConn=lp.CharacterAdded:Connect(function()
    task.wait(0.8);if tagsOn then buildTag(lp) end
  end)
end
buildSelf()
for _,p in ipairs(Players:GetPlayers())do tryTag(p)end
Players.PlayerAdded:Connect(function(p)
  if p==lp then return end
  p.CharacterAdded:Connect(function()task.wait(1);tryTag(p)end)
  task.wait(2);tryTag(p)
end)
Players.PlayerRemoving:Connect(removeTag)
task.spawn(function()
  while task.wait(5) do
    if tagsOn and mkr then
      for _,v in ipairs(mkr:GetChildren()) do
        local uid=tonumber(v.Name)
        if uid and uid~=lp.UserId then
          local p=Players:GetPlayerByUserId(uid)
          if p and not tagDB[p] then tryTag(p) end
        end
      end
    end
  end
end)

local function updTagBtn()
  if tagsOn then
    tagBtn.BackgroundColor3=Color3.fromRGB(22,10,44)
    tagBtn.TextColor3=Color3.fromRGB(170,90,255)
  else
    tagBtn.BackgroundColor3=Color3.fromRGB(40,14,14)
    tagBtn.TextColor3=Color3.fromRGB(210,80,80)
  end
end
updTagBtn()
tagBtn.MouseButton1Click:Connect(function()
  tagsOn=not tagsOn;updTagBtn()
  if tagsOn then
    buildSelf()
    for _,p in ipairs(Players:GetPlayers())do if p~=lp then tryTag(p) end end
    toast("AC ADMIN","Name tags ON",1.5)
  else
    if lp.Character then
      for _,n in ipairs({"ACTagF","ACTagL"}) do
        local t=lp.Character:FindFirstChild(n);if t then t:Destroy() end
      end
    end
    for p in pairs(tagDB) do removeTag(p) end;tagDB={}
    toast("AC ADMIN","Name tags OFF",1.5)
  end
end)

