    hvr(rB,rNC,Color3.fromRGB(42,20,76))
    rB.MouseButton1Click:Connect(function()
      rB.BackgroundColor3=Color3.fromRGB(28,14,55)
      rB.TextColor3=Color3.fromRGB(190,120,255);rB.Text="OK"
      toast("AC ADMIN",cmd.name.." started",1.8)
      task.delay(0.8,function()
        rB.BackgroundColor3=rNC
        rB.TextColor3=Color3.fromRGB(220,185,255);rB.Text="Run"
      end)
      safeRun(cmd.key)
    end)
    row.MouseEnter:Connect(function()tw(row,{BackgroundTransparency=0.15},0.1)end)
    row.MouseLeave:Connect(function()tw(row,{BackgroundTransparency=0.4},0.1)end)
  end
  rows[#rows+1]={row=row,cmd=cmd}
end

local function updC()
  local n=0
  for _,e in ipairs(rows)do if e.row.Visible then n=n+1 end end
  scr.CanvasSize=UDim2.new(0,0,0,n*44+4)
end
updC()

sBox:GetPropertyChangedSignal("Text"):Connect(function()
  local q=sBox.Text:lower():gsub("%s+","")
  for _,e in ipairs(rows)do
    if q=="" then e.row.Visible=true
    else
      local n2=e.cmd.name:lower():gsub("%s+","")
      local c2=e.cmd.cat:lower()
      local k2=e.cmd.key:lower()
      e.row.Visible=(n2:find(q,1,true) or c2:find(q,1,true) or k2:find(q,1,true))~=nil
    end
  end
  updC()
end)

local function togPnl()
  cmdOpen=not cmdOpen
  if cmdOpen then
    pnl.Visible=true;pnl.BackgroundTransparency=1
    tw(pnl,{BackgroundTransparency=0.42},0.18)
    sBox.Text=""
    for _,e in ipairs(rows)do e.row.Visible=true end;updC()
  else
    local t=TweenService:Create(pnl,
      TweenInfo.new(0.14,Enum.EasingStyle.Quart,Enum.EasingDirection.In),
      {BackgroundTransparency=1})
    t:Play();t.Completed:Connect(function()if not cmdOpen then pnl.Visible=false end end)
  end
end
cmdBtn.MouseButton1Click:Connect(togPnl)
pCl.MouseButton1Click:Connect(function()if cmdOpen then togPnl()end end)

